import{_ as t,o,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"How to Build OVMS for ESP32","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/ovms/how-to-build-ovms-for-esp32.md","filePath":"obd2/ovms/how-to-build-ovms-for-esp32.md"}'),i={name:"obd2/ovms/how-to-build-ovms-for-esp32.md"};function n(s,e,l,d,p,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="how-to-build-ovms-for-esp32" tabindex="-1">How to Build OVMS for ESP32 <a class="header-anchor" href="#how-to-build-ovms-for-esp32" aria-label="Permalink to &quot;How to Build OVMS for ESP32&quot;">​</a></h1><p>OVMS</p><br><p>Open Vehicle Monitoring System</p><p><br><br><br><img src="https://lh7-us.googleusercontent.com/hx_cUnzS0BUNWmsdXQIe9wyGBPcQzyU4YWd66PlMG2rFpvxfSgjt3bFb-RqBY3_Bu0oygYeUGokBz_HRBZsMhecsdBKoThSiiq-7tQv4p467V86IOJkaoGvbbdIGX7kVr-LnmQc4fBLP-f4nrahvjQ" alt=""></p><p><a href="http://www.openvehicles.com" target="_blank" rel="noreferrer">www.openvehicles.com<br><br></a>OVMS Developer Guide</p><p>v3.0.2 (24th August 2022)</p><p><br> For OVMS Hardware Module v3.x and Firmware v3.x.x</p><br><p>History</p><br><p>v3.0.0 20th Sep 2017 Initial version written</p><p>v3.0.1 20th Sep 2020 New chapter: Developing with Visual Studio Code</p><p>v3.0.2 24th Aug 2022 Minor edit to title of tools section for Linux/Mac</p><br><p>Table of Contents</p><br><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.x6wx14c7um3i" target="_blank" rel="noreferrer">Welcome 4</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.htuv6x7csnq0" target="_blank" rel="noreferrer">A short history of OVMS 4</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.t2ak98ld6zf9" target="_blank" rel="noreferrer">Development Overview 6</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.bx3i08hw9cn7" target="_blank" rel="noreferrer">Developing with Visual Studio Code (on Windows) 6</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.qc1x5iitc7w" target="_blank" rel="noreferrer">ESP-IDF (toolchain) 7</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.kzgsy1j1of0e" target="_blank" rel="noreferrer">Using a higher toolchain/xtensa version 7</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.87wcje3uoqbd" target="_blank" rel="noreferrer">Install OVMS’s own ESP-IDF 7</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.iq9ytb4muvpt" target="_blank" rel="noreferrer">Get and build the OVMS source code 8</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.bsn4e02cwh75" target="_blank" rel="noreferrer">Optional: Flashing the OVMS hardware directly 9</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.l16d3d7dj6qo" target="_blank" rel="noreferrer">Install USB driver for the OVMS 9</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.k8qy4s6pwthj" target="_blank" rel="noreferrer">Tell ESP-IDF the serial port 9</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.nfleuot8stv8" target="_blank" rel="noreferrer">Flash the OVMS 9</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.3cz8lao0yozf" target="_blank" rel="noreferrer">Install and configure portable Visual Studio Code and Git 9</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.u6jdm0jeydbr" target="_blank" rel="noreferrer">Install VSC portable 10</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.gwvg22j6k0iv" target="_blank" rel="noreferrer">Install Git for Windows portable 10</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.igp82pufjg8a" target="_blank" rel="noreferrer">Configure VSC 10</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.ln3pxsvpco17" target="_blank" rel="noreferrer">Coding OVMS in VSC 12</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.ps7gqk91cb3s" target="_blank" rel="noreferrer">Vehicle Firmware Development Tools (Linux/Mac) 13</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.346c9c4vxe87" target="_blank" rel="noreferrer">Module USB Development Port 15</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.q1djv6mrt3yo" target="_blank" rel="noreferrer">ESP-32 WROOM-32 Module eFuses 20</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.19hxbmisent8" target="_blank" rel="noreferrer">Vehicle Firmware Overview 21</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.lmwrnrfhp7kl" target="_blank" rel="noreferrer">Command Line Interpreter 21</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.t6s09orr514x" target="_blank" rel="noreferrer">OVMS Vehicle Modules 25</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.fh0kcxaejyzy" target="_blank" rel="noreferrer">Vehicle Metrics 28</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.pffpx5icm90" target="_blank" rel="noreferrer">Configuration 30</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.k0icuclfdl3m" target="_blank" rel="noreferrer">Access config flash filesystem 35</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.rggw49gq3ecc" target="_blank" rel="noreferrer">Module Circuit Design 37</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.nu2ueh2elr10" target="_blank" rel="noreferrer">Main Board Overview 37</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.qa5ilic49nox" target="_blank" rel="noreferrer">WROOM-32 and Support Circuits 38</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.dfxsex3f0swh" target="_blank" rel="noreferrer">128MB External SPI Flash 38</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.5boaosaifec9" target="_blank" rel="noreferrer">MAX7317 GPIO Expansion 39</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.c35d63don59a" target="_blank" rel="noreferrer">ESP32 Boot/Flash Control via USB 40</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.jjhtibd7zy25" target="_blank" rel="noreferrer">AOZ1280CI Power 41</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.unpcpexvrio9" target="_blank" rel="noreferrer">BTS452R Switched 12V Power 41</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.xjf0xsc19ker" target="_blank" rel="noreferrer">CP2102 USB 42</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.wvmpsm5vxa8q" target="_blank" rel="noreferrer">Micro SD Card 42</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.opia2rs096e6" target="_blank" rel="noreferrer">CAN Buses 45</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.zaey2jnok9tx" target="_blank" rel="noreferrer">CAN1 - On Board 45</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.elqrlm6k84i5" target="_blank" rel="noreferrer">CAN2 and CAN3 via MCP2515 45</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.3wzaabu7jje2" target="_blank" rel="noreferrer">Expansion 46</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.65lmef8k4svm" target="_blank" rel="noreferrer">Internal Expansion Bus 46</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.oxufbua9kmuu" target="_blank" rel="noreferrer">DA26 External Expansion Connector 46</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.l23dpridikk3" target="_blank" rel="noreferrer">DB9 External Expansion Connector 48</a></p><p><a href="https://docs.google.com/document/d/1q5M9Lb5jzQhJzPMnkMKwy4Es5YK12ACQejX_NWEixr0/edit#heading=h.p3p8tei5qmk6" target="_blank" rel="noreferrer">Conclusions 49</a></p><h2 id="welcome" tabindex="-1">Welcome <a class="header-anchor" href="#welcome" aria-label="Permalink to &quot;Welcome&quot;">​</a></h2><p>The OVMS (Open Vehicle Monitoring System) team is a group of enthusiasts who are developing a means to remotely communicate with our cars, and are having fun while doing it.</p><p></p><p>The OVMS module is a low-cost hardware device that you install in your car simply by installing a SIM card, connecting the module to your car’s Diagnostic port connector, and positioning a cellular antenna. Once connected, the OVMS module enables remote control and monitoring of your car.</p><p></p><p>This document presents an overview of the development tools and techniques you will need to work on the OVMS system. You might be extending what OVMS does already (either for general consumption, or for your own private use), adding support for a new vehicle, or using the OVMS framework to implement something completely different. Whatever your purpose, please remember that OVMS is an Open Source project without restrictions, that has got to where it is today by the contributions of so many; so please try to share what you yourself do with it.</p><h3 id="a-short-history-of-ovms" tabindex="-1">A short history of OVMS<img src="https://lh7-us.googleusercontent.com/YvqGbLe2iRHdUjblmub5GOnQTpmz4noOl2b4ugo_mGoxHjYliXknbwvXbadZxer3CNvfegzKX-puDjokgpDn3dI4HYs5eiD7Pkts-Cr2RgGwYO5hQ6s5W4Vy5Gb2-MwM0oxT8vw6Tli_DJ-C7RaG1w" alt=""> <a class="header-anchor" href="#a-short-history-of-ovms" aria-label="Permalink to &quot;A short history of OVMS![](https://lh7-us.googleusercontent.com/YvqGbLe2iRHdUjblmub5GOnQTpmz4noOl2b4ugo_mGoxHjYliXknbwvXbadZxer3CNvfegzKX-puDjokgpDn3dI4HYs5eiD7Pkts-Cr2RgGwYO5hQ6s5W4Vy5Gb2-MwM0oxT8vw6Tli_DJ-C7RaG1w)&quot;">​</a></h3><p>The Open Vehicle Monitoring System (OVMS) started out as a hobbyist project to bring cellphone control to the Tesla Roadster electric car. Three hobbyist, Michael Stegen, Mark Webb-Johnson, and Sonny Chen, built OVMS from the ground-up as an open source project.</p><br><p>The first batch of in-vehicle modules (now called ‘v1’) were hand-built in time for christmas 2011. These modules combined a vehicle control board (based on the PIC18F2680 processor) and a standard SIMCOM SIM900 cellular base board, housed in a relatively large white box.</p><br><p>In the early days, developers and those extremely technically capable were the only ones using OVMS, but as time went by more and more users wanted to benefit from cellular monitoring of their electric vehicles, and a community was born.</p><br><p>As the number of users grew, and the pain of hand-producing circuit boards got worse with volume, the developers started work on a new version of the hardware (now called ‘v2’). This would use a standard metal industrial enclosure, a single mass-produced PCB (with cellular or one side, and PIC18F2685 processor on the other), and most importantly an industry standard DB9 connector allow vehicles other than the Tesla Roadster to be supported via vehicle-specific adaptor cables. We also upgraded the SIMCOM to a SIM908 (and later SIM808) module, which supported GPS (for those vehicle types without onboard GPS). This new version was released late in 2012, with Fasttech (in China) as the distributor.</p><br><p>Both the v1 and v2 hardware modules used the same firmware code, and 2G SIMCOM modems. Over the years, the limitation of this hardware become more and more restrictive, as developers continued to push the limits with more vehicle support, and more advanced functionality. By 2016, a dozen vehicle types were supported, and both RAM and FLASH memory were at capacity. In addition, the phase-out of 2G by AT&amp;T in USA began to be an issue.</p><br><p>So, in 2017, the core development team began work on a version 3 (now called ‘v3’) of the OVMS module. This would be a complete re-write of the module firmware on a new platform:</p><p><br><img src="https://lh7-us.googleusercontent.com/WOtA5j2yi-3rcStN8uxSEnP06nbYsqMzxYmZdS5C3tA0mohZPzHavya8JWS6bBIVZVpx7ejmvAa_AebER9JTM4Ls7ZZS07ZKy-_4TX3z4T6CV8xDnK18Jc-FbTN60vYbGi-8vOYYrgE37PEA_UQfqA" alt=""></p><ul><li>Espressif IDF<br> (based on Open Source GNU C/C++)</li><li>ESP32 dual-core ARM processor</li><li>16MB flash and 520KB RAM</li><li>Wifi</li><li>Bluetooth</li><li>3x CAN buses</li><li>GPIO expansion ports</li><li>A new DB26 external expansion port</li><li>An internal expansion slot</li><li>SD CARD support</li><li>USB port</li><li>3G and 4G modem options</li></ul><br><p>The first ten v3 developer modules were produced in September 2017.</p><br><h3 id="development-overview" tabindex="-1">Development Overview <a class="header-anchor" href="#development-overview" aria-label="Permalink to &quot;Development Overview&quot;">​</a></h3><p></p><p>OVMS development can be divided into three main parts:</p><p></p><ol><li>Vehicle Firmware Development – working on the module inside vehicles.</li><li>Server Development – working with the OVMS server code.</li><li>App Development – working with the remote Apps that access the vehicle information.</li></ol><p></p><p>While some information presented here is specific to a particular area of development, in general we try to cover all three parts.</p><h2 id="developing-with-visual-studio-code-on-windows" tabindex="-1">Developing with Visual Studio Code (on Windows) <a class="header-anchor" href="#developing-with-visual-studio-code-on-windows" aria-label="Permalink to &quot;Developing with Visual Studio Code (on Windows)&quot;">​</a></h2><p>This chapter describes how you install and successfully build and flash OVMS using Visual Studio Code on Windows with the current (2020-07-14) version of OVMS. It may be applicable to other OSes as well. </p><br><p>This will be a portable installation. Meaning you can do everything on a flash drive and can take it to any other computer. You cannot (easily) just change the location on a computer though as some software saves their absolute path in their config. Nevertheless the whole installation won’t save anything in AppData/User/etc. folders. So a backup of the installation folder will backup everything.<br> In this example everything will be installed in D:\\OVMS which will be the root path and the user-name will be soko (change it to your Windows user name). The only important thing is that the whole path needs to be ASCII characters only with no spaces, symlinks or accents. </p><h3 id="esp-idf-toolchain" tabindex="-1">ESP-IDF (toolchain) <a class="header-anchor" href="#esp-idf-toolchain" aria-label="Permalink to &quot;ESP-IDF (toolchain)&quot;">​</a></h3><p>(Based on: <a href="https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/windows-setup.html" target="_blank" rel="noreferrer">https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/windows-setup.html</a>)</p><br><p>The current version of the OVMS specific ESP-IDF (<a href="https://github.com/openvehicles/esp-idf" target="_blank" rel="noreferrer">https://github.com/openvehicles/esp-idf</a>) is v3.3. So download the toolchain v3.3:</p><p><a href="https://dl.espressif.com/dl/esp32_win32_msys2_environment_and_toolchain_idf3-20200601.zip" target="_blank" rel="noreferrer">https://dl.espressif.com/dl/esp32_win32_msys2_environment_and_toolchain_idf3-20200601.zip</a></p><p>Open the ZIP-file and extract the content of its containing msys32 folder to C:\\OVMS so the path to mingw32.exe is C:\\OVMS\\mingw32.exe.</p><h4 id="using-a-higher-toolchain-xtensa-version" tabindex="-1">Using a higher toolchain/xtensa version <a class="header-anchor" href="#using-a-higher-toolchain-xtensa-version" aria-label="Permalink to &quot;Using a higher toolchain/xtensa version&quot;">​</a></h4><p>It can happen that the xtensa version in the zip file downloaded above is too old (happened 2020-07-16). The newer version should be lister at <a href="https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/windows-setup-scratch.html#updating-existing-windows-environment" target="_blank" rel="noreferrer">https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/windows-setup-scratch.html#updating-existing-windows-environment</a> under section “Alternative Setup: Just download a toolchain”. Download this zip file. Then goto C:\\OVMS\\opt , delete the xtensa-esp32-elf folder that’s in there and replace it with the one in the zip file.</p><h4 id="install-ovms-s-own-esp-idf" tabindex="-1">Install OVMS’s own ESP-IDF <a class="header-anchor" href="#install-ovms-s-own-esp-idf" aria-label="Permalink to &quot;Install OVMS’s own ESP-IDF&quot;">​</a></h4><p>Doubleclick on this mingw32.exe (don’t use mingw64.exe!). This is your environment bash shell.</p><p>Type in and execute:</p><p>$ git clone <a href="https://github.com/openvehicles/esp-idf.git" target="_blank" rel="noreferrer">https://github.com/openvehicles/esp-idf.git</a></p><p>$ cd esp-idf</p><p>$ git submodule update --init --recursive</p><p>$ cd ..</p><br><p>Now the OVMS specific version of ESP-IDF is on your computer. To later pull an ESP IDF update, issue:</p><p>$ cd esp-idf</p><p>$ git pull</p><p>$ git submodule update --recursive</p><p>$ cd ..</p><br><p>Now tell the toolchain the setup path of ESP-IDF by creating a new file named export_idf_path.sh in C:\\OVMS\\etc\\profile.d with the content</p><p>export IDF_PATH=&quot;C:/OVMS/home/soko/esp-idf&quot;</p><p>(use forward slashes and don’t forget to replace soko by your user name!).</p><br><p>Close the window and start mingw32.exe again. Type</p><p>$ printenv IDF_PATH</p><p>Which should give you the path you put into the file if everything is correct.</p><br><p>Next install the required python packages. To do so type</p><p>$ python -m pip install --user -r $IDF_PATH/requirements.txt</p><br><h3 id="get-and-build-the-ovms-source-code" tabindex="-1">Get and build the OVMS source code <a class="header-anchor" href="#get-and-build-the-ovms-source-code" aria-label="Permalink to &quot;Get and build the OVMS source code&quot;">​</a></h3><p>Type the following to get the latest version of OVMS from github:</p><p>$ git clone<a href="https://github.com/openvehicles/Open-Vehicle-Monitoring-System-3.git" target="_blank" rel="noreferrer"> https://github.com/openvehicles/Open-Vehicle-Monitoring-System-3.git</a></p><p>$ cd Open-Vehicle-Monitoring-System-3/vehicle/OVMS.V3</p><p>$ git submodule update --init --recursive</p><br><p>Next set the default build configurations: </p><p>$ cp support/sdkconfig.default.hw31 sdkconfig</p><p>$ make menuconfig</p><br><p>The last command will open a DOS-GUI window. Just choose “EXIT” for now which will close the window. After a while the prompt will come back.</p><br><p>If everything worked out as it should the source should build successfully by typing:</p><p>$ make -j17 all</p><br><p>The 17 behind -j should be the number of your CPU cores in your machine + 1 (so 17 for 16 cores). This option just speeds up the build process.</p><br><p>Congrats! You have now your own build OVMS firmware in the file</p><p>C:\\OVMS\\home\\soko\\Open-Vehicle-Monitoring-System-3\\vehicle\\OVMS.V3\\build\\ovms3.bin </p><br><p>You can now put this file onto a HTTP-server/website and use the firmware update option “OTA” on the OVMS web interface. Unfortunately there is no way to upload this file directly to OVMS.</p><h4 id="optional-flashing-the-ovms-hardware-directly" tabindex="-1">Optional: Flashing the OVMS hardware directly <a class="header-anchor" href="#optional-flashing-the-ovms-hardware-directly" aria-label="Permalink to &quot;Optional: Flashing the OVMS hardware directly&quot;">​</a></h4><p>As an option you can connect the OVMS box directly via USB to your computer and flash it. This may be dangerous though as a broken firmware may render your hardware inaccessible.</p><br><p><strong>Install USB driver for the OVMS</strong></p><p>So Windows recognize the OVMS as a virtual COM/Serial port a driver for the “CP210x USB to UART Bridge” is needed from here: <a href="https://www.silabs.com/products/development-tools/software/usb-to-uart-bridge-vcp-drivers" target="_blank" rel="noreferrer">https://www.silabs.com/products/development-tools/software/usb-to-uart-bridge-vcp-drivers</a></p><br><p>Download the correct version for your Windows version and unpack it somewhere. Plug in the OVMS via USB and point Windows to the unpacked folder when it asks for the driver.</p><br><p>Now you need to know the serial port name (i.e. “COM3”) the OVMS was installed as. Open the Windows Device Manager to find out.</p><p><strong>Tell ESP-IDF the serial port</strong></p><p>Start mingw32.exe again and type:</p><p>$ cd Open-Vehicle-Monitoring-System-3/vehicle/OVMS.V3</p><p>$ make menuconfig</p><br><p>Don’t close the DOS-GUI window. Instead choose “Serial flasher config” then the first entry “...Default serial port”. Delete whatever is written there, type COM3 and press Enter. Select EXIT two times and answer YES when asked if you want to save the changes.</p><p><strong>Flash the OVMS</strong></p><p>To build and flash, instead of just building type:</p><p>$ cp make -j17 flash</p><h3 id="install-and-configure-portable-visual-studio-code-and-git" tabindex="-1">Install and configure portable Visual Studio Code and Git <a class="header-anchor" href="#install-and-configure-portable-visual-studio-code-and-git" aria-label="Permalink to &quot;Install and configure portable Visual Studio Code and Git&quot;">​</a></h3><p>Programming with a decent IDE with Code Completion makes the day to day development so much easier. Here is how to use Visual Studio Code (VSC) and Git as portable installation. Until now you used the build in Git of ESP-IDF. VSC can’t use this unfortunately. This is why you have to install it again.</p><h4 id="install-vsc-portable" tabindex="-1">Install VSC portable <a class="header-anchor" href="#install-vsc-portable" aria-label="Permalink to &quot;Install VSC portable&quot;">​</a></h4><p>Download current version as a ZIP-file from <a href="https://code.visualstudio.com/download" target="_blank" rel="noreferrer">https://code.visualstudio.com/download</a></p><p>Unpack the content of the ZIP-file to C:\\OVMS\\VSC and then create the folder C:\\OVMS\\VSC\\data which will make the installation a portable installation.</p><h4 id="install-git-for-windows-portable" tabindex="-1">Install Git for Windows portable <a class="header-anchor" href="#install-git-for-windows-portable" aria-label="Permalink to &quot;Install Git for Windows portable&quot;">​</a></h4><p>Download the current version as portable EXE from <a href="https://git-scm.com/download/win" target="_blank" rel="noreferrer">https://git-scm.com/download/win</a></p><p>Use the EXE-File itself to unpack the content to C:\\OVMS\\GIT</p><p>Hint: The EXE-unpacking executes a batch file at the end which ties this installation to this absolute path. So it cannot be moved anymore afterwards.</p><h4 id="configure-vsc" tabindex="-1">Configure VSC <a class="header-anchor" href="#configure-vsc" aria-label="Permalink to &quot;Configure VSC&quot;">​</a></h4><p>Now it’s time to start VSC the first time with C:\\OVMS\\VSC\\Code.exe. This usually triggers the installation of the C/C++ IntelliSense extension. Just let it happen… It might also show up later when opening the OVMS folder.</p><p>Tell VSC the path of the portable Git installation by opening “File”, “Preferences”, “Settings”. Then “Extensions”, “Git” and scroll until you find the “Path” section. Click on “Edit in settings.json”. In file edit this line to:</p><p>&quot;git.path&quot;: &quot;C:\\\\OVMS\\\\GIT\\\\cmd\\\\git.exe&quot;</p><p>And save it. Close VSC for now.</p><br><p>To tell VSC how to cooperate with the OVMS Source you need some additional files. In the Windows Explorer create this folder (be aware it has a dot in front. So it’s “.vscode”. Depending on your Explorer settings it might not allow you to create such a folder or removes the dot automatically) c:\\OVMS\\home\\soko\\Open-Vehicle-Monitoring-System-3\\vehicle\\OVMS.V3\\.vscode\\ </p><br><p>Place the following three files with the listed content into this folder:</p><p>c_cpp_properties.json:</p><p>{</p><p> &quot;configurations&quot;: [</p><p> {</p><p> &quot;name&quot;: &quot;OVMS&quot;,</p><p> &quot;includePath&quot;: [</p><p> &quot;${workspaceFolder}&quot;,</p><p> &quot;${workspaceFolder}\\\\..\\\\..\\\\..\\\\esp-idf\\\\components\\\\**&quot;,</p><p> &quot;${workspaceFolder}\\\\**&quot;</p><p> ],</p><p> &quot;defines&quot;: [</p><p> &quot;_DEBUG&quot;,</p><p> &quot;UNICODE&quot;,</p><p> &quot;_UNICODE&quot;</p><p> ],</p><p> &quot;intelliSenseMode&quot;: &quot;msvc-x64&quot;</p><p> }</p><p> ],</p><p> &quot;version&quot;: 4</p><p>}</p><br><p>settings.json:</p><p>{</p><p> &quot;terminal.integrated.shell.windows&quot;: &quot;C:\\\\OVMS\\\\usr\\\\bin\\\\bash.exe&quot;,</p><p> &quot;terminal.integrated.shellArgs.windows&quot;: [&quot;--login&quot;],</p><p> &quot;terminal.integrated.env.windows&quot;: { </p><p> &quot;MSYSTEM&quot;: &quot;MINGW32&quot;, </p><p> &quot;CHERE_INVOKING&quot;:&quot;1&quot;</p><p> },</p><p> &quot;files.associations&quot;: {</p><p> &quot;forward_list&quot;: &quot;cpp&quot;</p><p> }</p><p>}</p><br><p>tasks.json (again change the -j17 to your number):</p><p>{</p><p> &quot;version&quot;: &quot;2.0.0&quot;,</p><p> &quot;tasks&quot;: [</p><p> {</p><p> &quot;type&quot;: &quot;shell&quot;,</p><p> &quot;label&quot;: &quot;ALL&quot;,</p><p> &quot;command&quot;: &quot;make -j17 all&quot;,</p><p> &quot;options&quot;: {</p><p> &quot;cwd&quot;: &quot;${workspaceFolder}&quot;</p><p> },</p><p> &quot;problemMatcher&quot;: [</p><p> &quot;$gcc&quot;</p><p> ],</p><p> &quot;group&quot;: {</p><p> &quot;kind&quot;: &quot;build&quot;,</p><p> &quot;isDefault&quot;: true</p><p> }</p><p> },</p><p> {</p><p> &quot;type&quot;: &quot;shell&quot;,</p><p> &quot;label&quot;: &quot;FLASH&quot;,</p><p> &quot;command&quot;: &quot;make -j17 flash&quot;,</p><p> &quot;options&quot;: {</p><p> &quot;cwd&quot;: &quot;${workspaceFolder}&quot;</p><p> },</p><p> &quot;problemMatcher&quot;: [</p><p> &quot;$gcc&quot;</p><p> ],</p><p> &quot;group&quot;: {</p><p> &quot;kind&quot;: &quot;build&quot;,</p><p> &quot;isDefault&quot;: true</p><p> }</p><p> },</p><p> {</p><p> &quot;type&quot;: &quot;shell&quot;,</p><p> &quot;label&quot;: &quot;CLEAN&quot;,</p><p> &quot;command&quot;: &quot;make -j17 clean&quot;,</p><p> &quot;options&quot;: {</p><p> &quot;cwd&quot;: &quot;${workspaceFolder}&quot;</p><p> },</p><p> &quot;problemMatcher&quot;: [</p><p> &quot;$gcc&quot;</p><p> ],</p><p> &quot;group&quot;: {</p><p> &quot;kind&quot;: &quot;build&quot;,</p><p> &quot;isDefault&quot;: true</p><p> }</p><p> }</p><p> ]</p><p> }</p><h4 id="coding-ovms-in-vsc" tabindex="-1">Coding OVMS in VSC <a class="header-anchor" href="#coding-ovms-in-vsc" aria-label="Permalink to &quot;Coding OVMS in VSC&quot;">​</a></h4><p>Start VSC again and choose “File”, “Open Folder…” and choose the folder</p><p>C:\\OVMS\\home\\soko\\Open-Vehicle-Monitoring-System-3\\vehicle\\OVMS.V3 </p><br><p>Now choose “Terminal”, “New Terminal” and press the “Accept”-Button on the windows that pop up. Open a New Terminal again. Now you should see the same shell as with mingw32.exe.</p><br><p>To build inside VSC just select “Terminal”, “Run Task” and then “ALL” which executes the “make -j17 all” command of the tasks.json file.</p><br><p>Have fun coding in VSC with IntelliSense and using it’s integrated Git features! It’s not as good as “Visual Studio 2019” but better than nothing 😉</p><br><h2 id="vehicle-firmware-development-tools-linux-mac" tabindex="-1">Vehicle Firmware Development Tools (Linux/Mac)<img src="https://lh7-us.googleusercontent.com/FuStMxordbXdlJpovykAWUTzJ0yzozmS9ivbcLE1WzYFvELtMaoFnh4xAoQ5NgzXKgoiIbtw0qlhIeFsP7RR2SA3FKkqJW6SP4ICY5ngAugxDoa0nN4ORwVPZWxxcBAmuAnyc_Cg-42vP5-6i1bulw" alt=""> <a class="header-anchor" href="#vehicle-firmware-development-tools-linux-mac" aria-label="Permalink to &quot;Vehicle Firmware Development Tools (Linux/Mac)![](https://lh7-us.googleusercontent.com/FuStMxordbXdlJpovykAWUTzJ0yzozmS9ivbcLE1WzYFvELtMaoFnh4xAoQ5NgzXKgoiIbtw0qlhIeFsP7RR2SA3FKkqJW6SP4ICY5ngAugxDoa0nN4ORwVPZWxxcBAmuAnyc_Cg-42vP5-6i1bulw)&quot;">​</a></h2><p>Version 3 (v3) of the Open Vehicle Monitor System module is based on an Espressif ESP-32 microcontroller module (Wifi and Bluetooth support, dual core ARM processor, RAM and FLASH).</p><br><p>The Software Development Kit used is Espressif’s ESP IDF, which is based on the open source GCC compiler plus a large number of support libraries and FreeRTOS based operating system. ESP IDF runs under Windows, Linux and Mac OSX.</p><br><p>You need to use the OVMS fork of the Espressif ESP IDF. It is a direct clone of the Espressif IDF, but includes some modifications especially for OVMS. You can find that here::</p><p><a href="https://github.com/openvehicles/esp-idf" target="_blank" rel="noreferrer">https://github.com/openvehicles/esp-idf</a></p><p>and you can find setup guides at the same place.</p><p><br> The usual installation steps are:</p><br><ol><li>Install pre-requisite tools</li><li>Install xtensa toolchain</li><li>Git clone the ESP IDF repository</li><li>Setup the environment</li></ol><br><p>The latest ESP IDF instructions are <a href="https://esp-idf.readthedocs.io/en/latest/get-started/index.html" target="_blank" rel="noreferrer">here</a>, (but don’t use the latest version of the esp-idf install instructions, because the OVMS fork is a couple of versions older) :<br><br></p><br><p>Use the esp-idf instructions for the <a href="https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/index.html" target="_blank" rel="noreferrer">release version matching the current OVMS branch version (currently: 3.3)</a></p><p><a href="https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/index.html" target="_blank" rel="noreferrer">https://docs.espressif.com/projects/esp-idf/en/release-v3.3/get-started/index.html</a></p><p>selected from the esp-idf-readthedocs.io documentation, to ensure that you get the correct versions of the prerequisites and toolchain.</p><br><p>After installing the prerequisites and the xtensa toolchain, Git clone the OVMS ESP IDF repository:</p><br><p>$ git clone <a href="https://github.com/openvehicles/esp-idf.git" target="_blank" rel="noreferrer">https://github.com/openvehicles/esp-idf.git</a></p><p>$ cd esp-idf</p><p>$ git submodule update --init --recursive</p><p><br><br></p><p>To later pull an ESP IDF update, issue:</p><br><p>$ cd esp-idf</p><p>$ git pull</p><p>$ git submodule update --recursive</p><br><p>Once you’ve got the Espressif ESP IDF installed, we recommend you try to compile one or more examples to make sure your environment works as expected.</p><br><p>Git clone the OVMS v3 repository and init the build configuration:</p><br><p>$ git clone <a href="https://github.com/openvehicles/Open-Vehicle-Monitoring-System-3.git" target="_blank" rel="noreferrer">https://github.com/openvehicles/Open-Vehicle-Monitoring-System-3.git</a></p><p>$ cd Open-Vehicle-Monitoring-System-3/vehicle/OVMS.V3</p><p>$ git submodule update --init --recursive</p><p>$ cd vehicle/OVMS.V3</p><p>$ cp support/sdkconfig.default.hw31 sdkconfig</p><p>$ make menuconfig</p><br><p>The config tool may prompt for some new config options, use the default values for all. Check the flasher serial port, leave other options at defaults.</p><br><p>Build and flash your first OVMS firmware to a connected V3 module:</p><br><p>$ make flash</p><br><p>Note to Mac OS X users with brew: If you have upgraded your OS, to High Sierra for instance, and you’ve already had tools installed via brew before: You will need to upgrade some component(s) such as bison as Apple has deeply modified some underlying libraries, otherwise you might end up having make commands fail. Launching the following command will download and install the adapted build even if it is the same version.</p><br><p>$ brew upgrade bison</p><br><p>This has been sufficient (with the proper paths) to get things working properly.</p><br><h2 id="module-usb-development-port" tabindex="-1">Module USB Development Port<img src="https://lh7-us.googleusercontent.com/FY0Kok1e42Q_0EvxdrvTpMqX21-m38e_WHtAQs2O1-T22nojMOHctH0z2Rko91Zhf0BPLa_iglXWZIHKyJtYDhNNmUD1BEDZ3wjrqxowRpMnaQ3UU9h-EmE221nPn-_2AH4xWOet9gjfCG3a2RiZaA" alt=""><img src="https://lh7-us.googleusercontent.com/eFy27to7__ldz9WLt-Ippdpg0JE2hI8psocc9mh19R7N0pn0oGI9J-dEdf3FtPPpQqop-GdC79m--7UjgXknr6RuhrFqQmxma_6i5WAuImk7j0Wb2pvmDeymQt33j5QF7vZGT04c1BDZYiKpcAAX-g" alt=""> <a class="header-anchor" href="#module-usb-development-port" aria-label="Permalink to &quot;Module USB Development Port![](https://lh7-us.googleusercontent.com/FY0Kok1e42Q_0EvxdrvTpMqX21-m38e_WHtAQs2O1-T22nojMOHctH0z2Rko91Zhf0BPLa_iglXWZIHKyJtYDhNNmUD1BEDZ3wjrqxowRpMnaQ3UU9h-EmE221nPn-_2AH4xWOet9gjfCG3a2RiZaA)![](https://lh7-us.googleusercontent.com/eFy27to7__ldz9WLt-Ippdpg0JE2hI8psocc9mh19R7N0pn0oGI9J-dEdf3FtPPpQqop-GdC79m--7UjgXknr6RuhrFqQmxma_6i5WAuImk7j0Wb2pvmDeymQt33j5QF7vZGT04c1BDZYiKpcAAX-g)&quot;">​</a></h2><p>The base OVMS module has a micro USB port next to the big DB26 expansion connector. This is the port connected to the ESP-32 microcontroller. It uses a Silicon Labs CP2102 USB-to-UART controller. If your operating system doesn’t have this driver already installed, you can download and install it from the Silicon Labs website.</p><br><p><a href="https://www.silabs.com/products/development-tools/software/usb-to-uart-bridge-vcp-drivers" target="_blank" rel="noreferrer">https://www.silabs.com/products/development-tools/software/usb-to-uart-bridge-vcp-drivers</a></p><br><p>Linux note: if your distribution includes the braille display driver “brltty”, you may need to uninstall that, as it claims any CP2102 device to be a braille device. This applies e.g. to openSuSE 15.0.</p><br><p>There is a second USB port on the optional modem board (above the GSM and GPS antennas, and next to the SIM card slot). This provides direct access to the USB on the SIMCOM modem module, and requires special SIMCOM drivers. It is used for firmware updates, and direct debugging of the SIMCOM module, so can generally be ignored.</p><p><br><img src="https://lh7-us.googleusercontent.com/oMh709pcuAU_qnlWfz-Qya-mYpKnepd_sTE7Hv_WNKziMbnhwr6ZRlT0_MbS5VMnNFAJfQ5WLSqB1tSWNVkgIqyBkcZaPAtpbXQf4gARApJDB2A87lwYubU3rWeYYNsG8hN3UvHgSZoNFWmK8IZXyA" alt="Yellow, Triangle, Border, Exclamation, Mark, Caution"></p><p>Note that OVMS v3 is currently in prototype stage, and has not received CE/FCC approval. In particular, while the v3.0 circuit board has protection diodes on the power supply pins, it will most likely require extra ESD and line noise filtering before approval. It is hobbyist kit.</p><p><br> As such, we recommend against directly connecting to the USB ports on your computer. Instead, please use a powered USB hub to ensure that the module receives adequate power, and there is some isolation between the module and your computer.</p><p><br><br></p><p>The module can be powered by USB (including the optional modem), and provides a serial console as well as flash programming capability. You can use Espressif’s ‘make monitor’ tool to connect to the module as a serial terminal.</p><br><p>$ make monitor</p><p>rst:0x1 (POWERON_RESET),boot:0x1f (SPI_FAST_FLASH_BOOT)</p><p>...</p><p>I (45) boot: ESP-IDF v2.1-2-g7138fb02 2nd stage bootloader</p><p>I (46) boot: compile time 09:50:02</p><p>I (79) boot: Enabling RNG early entropy source...</p><p>I (79) boot: SPI Speed : 40MHz</p><p>I (79) boot: SPI Mode : DIO</p><p>I (87) boot: SPI Flash Size : 16MB</p><p>I (100) boot: Partition Table:</p><p>I (111) boot: ## Label Usage Type ST Offset Length</p><p>I (134) boot: 0 nvs WiFi data 01 02 00009000 00004000</p><p>I (157) boot: 1 otadata OTA data 01 00 0000d000 00002000</p><p>I (180) boot: 2 phy_init RF data 01 01 0000f000 00001000</p><p>I (204) boot: 3 factory factory app 00 00 00010000 00400000</p><p>I (227) boot: 4 ota_0 OTA app 00 10 00410000 00400000</p><p>I (250) boot: 5 ota_1 OTA app 00 11 00810000 00400000</p><p>I (273) boot: 6 store Unknown data 01 81 00c10000 00100000</p><p>...</p><p>I (1755) heap_alloc_caps: Initializing. RAM available for dynamic allocation:</p><p>I (1778) heap_alloc_caps: At 3FFAFF10 len 000000F0 (0 KiB): DRAM</p><p>I (1798) heap_alloc_caps: At 3FFC9D20 len 000162E0 (88 KiB): DRAM</p><p>I (1819) heap_alloc_caps: At 3FFE0440 len 00003BC0 (14 KiB): D/IRAM</p><p>I (1840) heap_alloc_caps: At 3FFE4350 len 0001BCB0 (111 KiB): D/IRAM</p><p>I (1862) heap_alloc_caps: At 40094FD0 len 0000B030 (44 KiB): IRAM</p><p>...</p><p>I (1883) cpu_start: Pro cpu start user code</p><p>I (1940) command: Initialising COMMAND (1000)</p><p>I (1952) events: Initialising EVENTS (1200)</p><p>I (1954) config: Initialising CONFIG (1400)</p><p>...</p><p>I (1556) ovms_main: Starting HOUSEKEEPING...</p><p>I (1556) housekeeping: Initialising HOUSEKEEPING Framework...</p><p>I (1616) housekeeping: Executing on CPU core 1</p><p>I (1616) housekeeping: Starting PERIPHERALS...</p><p>I (1616) peripherals: Initialising OVMS Peripherals...</p><p>I (1626) peripherals: ESP32 system</p><p>I (1626) peripherals: SPI bus</p><p>I (1626) peripherals: MAX7317 I/O Expander</p><p>I (1636) peripherals: ESP32 CAN</p><p>I (1636) peripherals: ESP32 WIFI</p><p>I (1646) peripherals: ESP32 BLUETOOTH</p><p>I (1646) peripherals: ESP32 ADC</p><p>I (1656) peripherals: MCP2515 CAN 1/2</p><p>I (1656) peripherals: MCP2515 CAN 2/2</p><p>I (1666) peripherals: SD CARD</p><p>I (1666) peripherals: SIMCOM MODEM</p><p>I (1666) housekeeping: Starting USB console...</p><br><p>Welcome to the Open Vehicle Monitoring System (OVMS) - Async Console</p><p>OVMS &gt;</p><p>There are some important things shown in that boot screen, so let’s look in some detail.</p><br><p>$ make monitor</p><p>rst:0x1 (POWERON_RESET),boot:0x1f (SPI_FAST_FLASH_BOOT)</p><br><p>The OVMS v3 module includes two push-button switches on the motherboard, BOOT and ENABLE. Pressing the ENABLE switch will reset the processor. Holding down the BOOT switch, while pressing ENABLE, will boot into firmware download mode.</p><br><p>To simplify development, and flashing of modules, OVMS includes some transistor logic controlled by async control lines (RTS, DTR, etc) to control this ENABLE and BOOT functionality. When you type “make flash”, Espressif will connect to the serial port, then manipulate the control lines to hold down BOOT and then toggle ENABLE, to switch to firmware download mode. By default, every time you type “make monitor”, Espressif will also toggle the ENABLE pin to reset the device. You can change this behaviour in “make menuconfig”, or use your own terminal emulator, to avoid this (if you don’t want it).</p><br><p>I (45) boot: ESP-IDF v2.1-2-g7138fb02 2nd stage bootloader</p><p>I (46) boot: compile time 09:50:02</p><p>I (79) boot: Enabling RNG early entropy source...</p><p>I (79) boot: SPI Speed : 40MHz</p><p>I (79) boot: SPI Mode : DIO</p><p>I (87) boot: SPI Flash Size : 16MB</p><br><p>The default flash in the ESP-32 WROOM-32 module we use is 4MB, but that is insufficient. So, OVMS includes an external 16MB flash and the ESP-32 chips we use are modified to permanently burn fuses inside the chip, in order to select and use this external flash. At the moment, we are using 40Mhz DIO mode to access this chip; but we may switch to QIO mode and increase the speed later when we are comfortable with the performance requirements and stability.</p><br><p>I (100) boot: Partition Table:</p><p>I (111) boot: ## Label Usage Type ST Offset Length</p><p>I (134) boot: 0 nvs WiFi data 01 02 00009000 00004000</p><p>I (157) boot: 1 otadata OTA data 01 00 0000d000 00002000</p><p>I (180) boot: 2 phy_init RF data 01 01 0000f000 00001000</p><p>I (204) boot: 3 factory factory app 00 00 00010000 00400000</p><p>I (227) boot: 4 ota_0 OTA app 00 10 00410000 00400000</p><p>I (250) boot: 5 ota_1 OTA app 00 11 00810000 00400000</p><p>I (273) boot: 6 store Unknown data 01 81 00c10000 00100000</p><br><p>By default, OVMS partitions this 16MB flash to NVS (general parameter=value key storage), otadata (control data for the Over-The-Air update facility), phy_init (RF data), factory (the firmware App flashed at the factory), ota_1 (OTA image #1), ota_2 (OTA image #2), and store (a FAT filesystem mounted as /store during boot).</p><br><p>The factory, ota_0 and ota_1 partitions are all 4MB in size - and that is the largest firmware image that can be loaded onto the chip. The otadata partition contains a pointer to one of these three partitions, to tell the bootloader which to map to during boot.</p><br><p>When first delivered, we will be running the factory firmware in the factory partition, and otadata will point to that. If an Over-The-Air update is performed, it will be downloaded to ota_0 and otadata modified to point to ota_0. Upon next reboot, the bootloader will then run the image in ota_0. If a second Over-The-Air update is performed, while running in ota_0 partition, it will be flashed to ota_1, and then otadata modified to point to ota_1. Note that all the operating addressing of all these images is the same, irrespective of the partition offset in the flash - the bootloader deals with mapping physical memory to these partitions, via it’s cache. If the bootloader fails to boot into an OTA partition, it will fall back to the factory partition. In this way, the factory partition is always there as a backup.</p><br><p>Note that ‘make flash’ will flash all these partitions (including bootloader, partition table, factory partition, etc). Generally, it is quicker to ‘make app-flash’ to flash just the factory application partition.</p><br><p>I (1755) heap_alloc_caps: Initializing. RAM available for dynamic allocation:</p><p>I (1778) heap_alloc_caps: At 3FFAFF10 len 000000F0 (0 KiB): DRAM</p><p>I (1798) heap_alloc_caps: At 3FFC9D20 len 000162E0 (88 KiB): DRAM</p><p>I (1819) heap_alloc_caps: At 3FFE0440 len 00003BC0 (14 KiB): D/IRAM</p><p>I (1840) heap_alloc_caps: At 3FFE4350 len 0001BCB0 (111 KiB): D/IRAM</p><p>I (1862) heap_alloc_caps: At 40094FD0 len 0000B030 (44 KiB): IRAM</p><br><p>Memory is limited. This is an embedded system. Take care.</p><br><p>I (1883) cpu_start: Pro cpu start user code</p><p>I (1940) command: Initialising COMMAND (1000)</p><p>I (1952) events: Initialising EVENTS (1200)</p><p>I (1954) config: Initialising CONFIG (1400)</p><br><p>OVMS boots in a very defined order. If you need a component to hook into this initialisation system, it is generally best to contact the lead developers for information on where precisely to hook in.</p><br><p>I (1556) ovms_main: Starting HOUSEKEEPING...</p><p>I (1556) housekeeping: Initialising HOUSEKEEPING Framework...</p><p>I (1616) housekeeping: Executing on CPU core 1</p><p>I (1616) housekeeping: Starting PERIPHERALS...</p><p>I (1616) peripherals: Initialising OVMS Peripherals...</p><p>I (1626) peripherals: ESP32 system</p><p>I (1626) peripherals: SPI bus</p><p>I (1626) peripherals: MAX7317 I/O Expander</p><p>I (1636) peripherals: ESP32 CAN</p><p>I (1636) peripherals: ESP32 WIFI</p><p>I (1646) peripherals: ESP32 BLUETOOTH</p><p>I (1646) peripherals: ESP32 ADC</p><p>I (1656) peripherals: MCP2515 CAN 1/2</p><p>I (1656) peripherals: MCP2515 CAN 2/2</p><p>I (1666) peripherals: SD CARD</p><p>I (1666) peripherals: SIMCOM MODEM</p><p>I (1666) housekeeping: Starting USB console...</p><br><p>Welcome to the Open Vehicle Monitoring System (OVMS) - Async Console</p><p>OVMS &gt;</p><br><p>Once the boot is complete, you’ll be presented with the OVMS async console prompt, and can type commands.</p><br><h2 id="esp-32-wroom-32-module-efuses" tabindex="-1">ESP-32 WROOM-32 Module eFuses <a class="header-anchor" href="#esp-32-wroom-32-module-efuses" aria-label="Permalink to &quot;ESP-32 WROOM-32 Module eFuses&quot;">​</a></h2><p>As part of the factory production process for OVMS v3, we custom burn some ESP-32 eFuses on the WROOM-32 module to suite our requirements (in particular for external 16MB flash). If you ever replace the WROOM-32 module, or wish to use custom hardware with OVMS firmware and flash partition layout, you will need to custom-burn these eFuses. Below is the documentation for what we do.</p><br><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse XPD_SDIO_REG 1</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse XPD_SDIO_TIEH 1</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse XPD_SDIO_FORCE 1</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse SPI_PAD_CONFIG_CLK 6</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse SPI_PAD_CONFIG_Q 7</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse SPI_PAD_CONFIG_D 8</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse SPI_PAD_CONFIG_HD 9</p><p>espefuse.py -p &lt;path-to-uart&gt; burn_efuse SPI_PAD_CONFIG_CS0 22</p><br><p>If you do it right, it will look like this:</p><br><p>Config fuses:</p><p>XPD_SDIO_FORCE Ignore MTDI pin (GPIO12) for VDD_SDIO on reset = 1 R/W (0x1)</p><p>XPD_SDIO_REG If XPD_SDIO_FORCE, enable VDD_SDIO reg on reset = 1 R/W (0x1)</p><p>XPD_SDIO_TIEH If XPD_SDIO_FORCE &amp; XPD_SDIO_REG, 1=3.3V 0=1.8V = 1 R/W (0x1)</p><p>SPI_PAD_CONFIG_CLK Override SD_CLK pad (GPIO6/SPICLK) = 6 R/W (0x6)</p><p>SPI_PAD_CONFIG_Q Override SD_DATA_0 pad (GPIO7/SPIQ) = 7 R/W (0x7)</p><p>SPI_PAD_CONFIG_D Override SD_DATA_1 pad (GPIO8/SPID) = 8 R/W (0x8)</p><p>SPI_PAD_CONFIG_HD Override SD_DATA_2 pad (GPIO9/SPIHD) = 9 R/W (0x9)</p><p>SPI_PAD_CONFIG_CS0 Override SD_CMD pad (GPIO11/SPICS0) = 22 R/W (0x16)</p><p>DISABLE_SDIO_HOST Disable SDIO host = 0 R/W (0x0)</p><br><p>Note that this is a one-time operation. Once these eFuses are burned, the change is permanent and irreversible.</p><h2 id="vehicle-firmware-overview" tabindex="-1">Vehicle Firmware Overview <a class="header-anchor" href="#vehicle-firmware-overview" aria-label="Permalink to &quot;Vehicle Firmware Overview&quot;">​</a></h2><h3 id="command-line-interpreter" tabindex="-1">Command Line Interpreter <a class="header-anchor" href="#command-line-interpreter" aria-label="Permalink to &quot;Command Line Interpreter&quot;">​</a></h3><p>NOTE: This documentation is no longer maintained. Please see <a href="https://docs.openvehicles.com/en/latest/cli/index.html" target="_blank" rel="noreferrer">https://docs.openvehicles.com/en/latest/cli/index.html</a> for the current documentation.</p><br><p>The command line interpreter or command parser presented by the OVMS async serial console is constructed as a tree of command word tokens. Enter a single &quot;?&quot; followed by &lt;RETURN&gt; to get the root command list, like this:</p><br><p>OVMS# ?</p><p>. Run a script</p><p>bms BMS framework</p><p>boot BOOT framework</p><p>can CAN framework</p><p>...</p><br><p>A root command may be followed by one of a list of additional tokens called subcommands which in turn may be followed by further subcommands down multiple levels. The command and subcommand tokens may be followed by parameters. Use &quot;?&quot; at any level in the command</p><p>sequence to get the list of subcommands applicable at that point. If the next item to be entered is a parameter rather than a subcommand, then a usage message will be displayed to indicate the required or optional parameters. The usage message will also be shown if the command as entered is not valid. The usage message is described in further detail below.</p><br><p>Command tokens can be abbreviated so long as enough characters are entered to uniquely identify the command, then optionally pressing &lt;TAB&gt; will auto-complete the token. If the abbreviated form is not sufficient to be unique (in particular if no characters have been </p><p>entered yet) then &lt;TAB&gt; will show a concise list of the possible subcommands and then retype the portion of the command line already entered so it can be completed. Pressing &lt;TAB&gt; is legal at any point in the command; if there is nothing more that can be completed automatically then there will just be no response to the &lt;TAB&gt;.</p><br><p>The OvmsCommand::RegisterCommand() function is used to add command and subcommand tokens are added to the tree. New commands are added to the root of the tree using the global MyCommandApp.RegiserCommand(). Subcommands are added as children of a command using the OvmsCommand pointer returned when RegisterCommand() is called for the parent, thus building the tree. For example:</p><br><p>OvmsCommand* cmd_wifi = MyCommandApp.RegisterCommand(&quot;wifi&quot;,&quot;WIFI framework&quot;, wifi_status);</p><p>cmd_wifi-&gt;RegisterCommand(&quot;status&quot;,&quot;Show wifi status&quot;,wifi_status);</p><p>cmd_wifi-&gt;RegisterCommand(&quot;reconnect&quot;,&quot;Reconnect wifi client&quot;,wifi_reconnect);</p><br><p>The RegisterCommand() function takes the following arguments:</p><br><ul><li>const char* name – the command token</li><li>const char* title – one-line description for command list</li><li>void (*execute)(...) – does the work of the command</li><li>const char *usage – the &quot;Usage:&quot; line describing parameters</li><li>int min – minimum number of parameters allowed</li><li>int max – maximum number of parameters allowed</li><li>bool secure – true for commands permitted only after &quot;enable&quot;</li><li>int (*validate)(...) – validates parameters as explained later</li></ul><br><p>It&#39;s important to note that many of these arguments can and should be defaulted. The default values are as follows:</p><br><ul><li>execute = NULL</li><li>usage = &quot;&quot;</li><li>min = 0</li><li>max = 0</li><li>secure = true</li><li>validate = NULL</li></ul><br><p>For example, for secure, non-terminal commands, such as the top-level &quot;framework&quot; commands like &quot;bms&quot; in the list of root commands shown earlier, the model should simply be:</p><br><p>RegisterCommand(&quot;name&quot;, &quot;Title&quot;);</p><br><p>For secure, terminal (sub)commands that don&#39;t require any additional parameters, the model should be:</p><br><p>RegisterCommand(&quot;name&quot;, &quot;Title&quot;, execute);</p><br><p>This model also applies if the command has children but the command itself wants to execute a default operation if no subcommand is specified. It is incorrect to specify min = 0, max = 1 to indicate an optional subcommand; that is indicated by the presence of the execute function at the same time as a non-empty children array.</p><br><p>Any command with required or optional parameters should provide a usage string hinting about the parameters in addition to specifying the minimum and maximum number of parameters allowed:</p><br><p>RegisterCommand(&quot;name&quot;, &quot;Title&quot;, execute, &quot;usage&quot;, min, max);</p><br><p>The usage argument only needs to describe the parameters that follow this (sub)command because the full usage message is dynamically generated. The message begins with the text &quot;Usage: &quot; followed by names of the ancestors of the this (sub)command back to the root of the tree plus the name of this (sub)command itself. That is, the message starts with all the tokens entered to this point followed by additional description of subcommands or parameters that may be entered next, as determined by the usage string.</p><br><p>The usage string syntax conventions for specifying alternative and optional parameters are similar to those of usage messages in Unix-like systems. The string can also include special codes to direct the dynamic generation of the message:</p><br><ul><li>$C expands to the list of children commands as child1|child2|child3.</li><li>[$C] expands to optional children as [child1|child2|child3].</li><li>$G$ expands to the usage string of the first child; this would typically used after $C so the usage message shows the list of children and then the parameters or next-level subcommands that can follow the children. This is useful when the &quot;usage&quot; string is the same for all or most of the children as in this example:</li></ul><br><p>Usage: power adc|can1|can2|can3|egpio|esp32|sdcard|simcom|spi|wifi deepsleep|devel|off|on|sleep|status</p><br><ul><li>$Gfoo$ expands to the usage of the child named &quot;foo&quot;; this variant would be used when not all the children have the same usage but it would still be helpful to show the usage of one that&#39;s not first.</li><li>$L lists a separate full usage message for each of the children. This provides more help than just showing the list of children but at the expense of longer output.</li><li>For terminal (sub)commands (those with no children) that take additional parameters, the usage string contains explicit text to list the parameters:</li></ul><ul><li><ul><li>Parameter names or descriptions are enclosed in angle brackets to distinguish the them from command tokens, for example &quot;&lt;metric&gt; &lt;value&gt;&quot;.</li><li>Parameters that are optional are further enclosed in square brackets, like</li></ul></li></ul><p>&quot;&lt;id&gt; &lt;name&gt; [&lt;value&gt;]&quot;.</p><ul><li>When there are alternative forms or meanings for a parameter, the alternatives are separated by vertical bar as in &quot;[&lt;task names or ids&gt;|*|=]&quot; which indicates that the parameter can be either of the characters &#39;*&#39; or &#39;=&#39; instead of a list of task names or ids. An variant form encloses the alternatives in curly braces as in</li></ul><p>&quot;&lt;param&gt; {&lt;instance&gt; | *}&quot;.</p><ul><li>One or more additional lines of explanatory text can be included like this: &quot;&lt;id&gt;\\nUse ID from connection list / 0 to close all&quot;.</li></ul><br><p>For non-terminal commands (those with children subcommands) the usage argument can be omitted because the default value of &quot;&quot; is interpreted as &quot;$C&quot;. For commands that have children subcommands that are optional (because an execute function is included) the default usage argument is interpreted as “[$C]”.</p><br><p>Most commands do not need to specify a validate function. It supports two extensions of the original command parser design:</p><br><ol><li>For commands that store the possible values of a parameter in a NameMap&lt;T&gt; or CNameMap&lt;T&gt;, the validate function enables &lt;TAB&gt; auto-completion when entering that parameter. For example, see the &quot;config&quot; command in main/ovms_config.cpp.</li><li>The original design only allowed parameters to be collected by the terminal subcommand. That forced an unnatural word order for some commands. The validate function enables non-terminal subcommands to take one or more parameters followed by multiple children subcommands. The parameters may allow &lt;TAB&gt; completion if the possible values are stored in NameMap&lt;T&gt; or CNameMap&lt;T&gt; or they could be something else like a number that can be validated by value. The validate function must indicate success for parsing to continue to the children subcommands. The return value is the number of parameters validated if successful or -1 if not.</li></ol><br><p>The &quot;location&quot; command is an example that includes an intermediate parameter and also utilizes the &quot;$L&quot; form of the usage string:</p><br><p>OVMS# location action enter ?</p><p>Usage: location action enter &lt;location&gt; acc &lt;profile&gt;</p><p>Usage: location action enter &lt;location&gt; homelink 1|2|3</p><p>Usage: location action enter &lt;location&gt; notify &lt;text&gt;</p><br><p>See components/ovms_location/src/ovms_location.cpp for the implementation of the location_validate() function and the RegisterCommand() calls to build the command subtree.</p><p><br><br></p><h2 id="ovms-vehicle-modules" tabindex="-1">OVMS Vehicle Modules <a class="header-anchor" href="#ovms-vehicle-modules" aria-label="Permalink to &quot;OVMS Vehicle Modules&quot;">​</a></h2><p>All functionality to support a particular type of vehicle should be implemented in OVMS vehicle modules. These are in the following directories:</p><br><p>components/vehicle_*</p><br><p>Steps to take, to stub support for a new vehicle type, are:</p><br><ol><li>Decide on a short type code for the vehicle (upper case, minimum two characters), that doesn’t conflict with any existing vehicle (vehicle list shows the currently defined vehicles). Build the code from an abbreviation of the brand/manufacturer and an abbreviation of the vehicle. Examples:</li><li><ol><li>TR – Tesla Roadster</li><li>RT – Renault Twizy</li><li>VWUP – VW e-Up</li></ol></li></ol><br><ol start="2"><li>Decide on a long vehicle name. This is normally just the vehicle name itself (such as “Tesla Roadster”).<br><br></li><li>Decide on a unique log tag to use in all your modules. Use prefix “v-” followed by a lower case short name of the vehicle for the log tag. The logging system allows to set different log levels per log tag. See existing vehicle modules for reference on how to define and use the log tag. Examples:</li><li><ol><li>“v-twizy”</li><li>“v-vweup”</li><li>“v-bmwi3”<br><br></li></ol></li><li>Decide on a unique namespace prefix for your custom configuration, metrics and commands. The custom namespace shall be a lower case code beginning with “x” followed by at least two characters for the vehicle type. Try to keep this at three characters in length. Examples:</li><li><ol><li>“xrt” – Renault Twizy</li><li>“xvu” – VW e-Up</li><li>“xi3” – BMW i3/i3s<br><br></li></ol></li><li>Create the directory structure<br><br> components/vehicle_&lt;lower-case-long-name&gt;<br> /component.mk<br> /src<br> /vehicle_&lt;lower-case-long-name&gt;.{h,cpp}<br><br> You can use vehicle_none as a template for this.<br><br></li><li>Change main/Kconfig to add a menu configuration item in the “Vehicle Support” section<br><br> OVMS_VEHICLE_&lt;upper-case-long-name&gt;<br><br></li><li>Change your component.mk to selectively compile in support for your vehicle, based on that CONFIG_OVMS_VEHICLE_* menu configuration.<br><br></li><li>Add all the above to git, make sure it compiles, commit and push.</li></ol><br><p>Once basic support is stubbed, as above, you can start work on actual implementation of the vehicle module. We suggest you look at vehicle_teslaroadster for a practical example of how things should be done. These notes may help.</p><br><ul><li>A short OvmsVehicleXXXInit object handles registration of your vehicle name, with associated vehicle implementation object, at init_priority 9000. All vehicle initialise at this priority level, unless they are dependent on other vehicle modules.<br><br></li><li>A reception queue, and task, will be created and managed for you automatically.<br><br></li><li>Create a member function “void IncomingFrameCan1(CAN_frame_t* p_frame)” in your vehicle implementation object. This will be used to receive incoming CAN bus messages on CAN bus #1. You can also create IncomingFrameCan2 and IncomingFrameCan3 for the other two buses (if you require). The vehicle framework will automatically deliver CAN bus messages to your functions.<br><br><br></li><li>Implement the constructor for your vehicle implementation. You will need to define the CAN buses your vehicle requires in the vehicle constructor function, with RegisterCanBus(int bus, CAN_mode_t mode, CAN_speed_t speed). Here is a simple example:<br><br> OvmsVehicleTeslaRoadster::OvmsVehicleTeslaRoadster()<br> {<br> ESP_LOGI(TAG, &quot;Tesla Roadster v1.x, v2.x and v3.0 vehicle module&quot;);<br> RegisterCanBus(1,CAN_MODE_ACTIVE,CAN_SPEED_1000KBPS);<br> }<br><br></li><li>Implement a destructor for your vehicle implementation to perform any necessary cleanup. The base vehicle module destructor will automatically handle cleanup of the task, queue, and any CAN buses you are using.<br><br></li><li>Implement your IncomingFrameCanX handlers to process the incoming CAN frames. You will usually be decoding the messages, and updating metrics with the decoded vehicle data, appropriately.</li></ul><br><p>You can use the ‘vehicle set …’ console command to switch to your vehicle.</p><br><p>Note that vehicle specific command registration can also be made in the OvmsVehicleXXXInit constructor. This is the preferred mechanism for implementing vehicle-specific commands. You can use MyVehicleFactory.m_currentvehicle to make sure a vehicle is currently set to run, and VehicleName() on that, to ensure it is your vehicle type.</p><h2 id="vehicle-metrics" tabindex="-1">Vehicle Metrics <a class="header-anchor" href="#vehicle-metrics" aria-label="Permalink to &quot;Vehicle Metrics&quot;">​</a></h2><p>OVMS v3 is all about ‘metrics’. Vehicle modules update the metrics, and apps consume them via network protocols. A metric is a single piece of information, and its associated current value.</p><br><p>The metrics subsystem is implemented in main/ovms_metrics.{h,cpp} as a C++ object. The primary interface to metrics is via the MyMetrics static object. Using that interface, new metrics can be registered, and values set. In addition, listeners can be established to be notified whenever a particular metric changes.</p><br><p>The metrics themselves are implemented in a virtual base class OvmsMetric. Currently, OVMS supports metrics of types boolean (OvmsMetricBool), integer (OvmsMetricInt), floating point (OvmsMetricFloat) and string (OvmsMetricString). All metric types support the base functionality on OvmsMetric for setting and reading the current value as strings (converting as necessary to the base data type), as well as indicators for whether an initial value has been defined, and for tracking modifications.</p><br><p>A global METRICS_MAX_MODIFIERS is used to define the maximum number of Modifiers (services tracking modifications to metrics). This is implemented internally as a bitmask. Every time a metric is modified, all the bits are set true. Then, individual modifiers can track their own individual bit, and clear as necessary. Modifiers themselves register to receive their own unique modifier bit number with MyMetrics.RegisterModifier(). In this way, modifiers can choose to use their modifier bit as they see fit. For example, the server protocols register as modifiers and clear their modifier bit when they send the data to the server; in this way, they can reduce the data transmissions by only sending modified metrics.</p><br><p>Standardised metrics are automatically registered on system boot by the code in main/metrics_standard.{h,cpp}. In addition, a static object StandardMetrics is defined, with member variables pointing to each of the standard metrics. This allows fast, efficient, type safe, access to the standardised metrics. For example:</p><br><p>StandardMetrics.m_v_bat_soc-&gt;SetValue(42);</p><br><p>Vehicle-specific metrics can be registered and maintained by individual vehicle modules. In most cases, a vehicle module should maintain a pointer to the registered metric (using a member variable of the vehicle object) for fast and efficient access. The registration itself is automatic (all that is necessary is to create a metric object from one of the OvmsMetric derived metric types, and they will be registered automatically, by name). In most cases, the vehicle module initialisation should use MyMetrics.Find(name) to search for a metric by name and store the resulting pointer. If not found, the metric should be first-time registered.</p><br><p>There are some console commands available to view and manipulate the metrics (for diagnostic and testing purposes):</p><br><p>OVMS &gt; metrics list</p><p>m.freeram 46716</p><p>m.hardware OVMS WIFI BLE BT cores=2 rev=ESP32/1</p><p>m.serial aa:bb:cc:dd:ee:ff</p><p>m.tasks 18</p><p>m.version 3.0.0/factory/main build Sep 22 2017 06:33:43</p><p>s.v2.connected yes</p><p>s.v2.peers 0</p><p>v.b.12v 0</p><br><p>OVMS &gt; metrics set &lt;metric&gt; &lt;value&gt;</p><br><p>Metrics have several common attributes that deserve further explanation:</p><br><ul><li>Last Modified Date: This is accessible via LastModified(). Note that this date is the time the metric was last updated. If a metric is updated, but the value is unchanged, the last modified date will be updated, but the modified bit flags will not.<br><br></li><li>Stale: This is accessible via IsStale(), and setable via SetStale(bool stale). Whenever a metric is updated (irrespective of whether the value has been changed or not), the stale flag is cleared.<br><br></li><li>AutoStale: This is configurable when the metric object is created, or with the SetAutoStale(int seconds) function. If set (non zero), the stale flag will be automatically set if the metric value has not been updated for the specified number of seconds.</li></ul><br><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The configuration for OVMS v3 is stored on ESP32 flash, under vfs mount /store/ovms_config. Under normal configuration, that is a protected path and the normal VFS operations (cp, cat, etc) will not be permitted. As a developer, you can disable that protection via a menuconfig option (Component Config -&gt; OVMS -&gt; Developer Options -&gt; “Disable the usual protections for configuration visibility in VFS”).</p><br><p>The general design of the configuration store is that configuration items are identified by:</p><br><p>Parameter [instance] = value</p><br><p>The parameters must be registered, usually during boot-time initialisation:</p><br><p>RegisterParam(</p><p> std::string name,</p><p> std::string title,</p><p> bool writeable=true,</p><p> bool readable=true);</p><br><p>The ‘writable’ and ‘readable’ flags control whether the user has write and/or read access to all the instances and values within that parameter. Firmware modules themselves always have full read/write access, and these only control user console access permissions. For example, you might set a store for passwords as writable=true, readable=false, so users could set passwords, but not view them. Similarly, a parameter maintained by a firmware module (and not the user) might be writable=false, readable=true.</p><br><p>If you don’t require an instance, then simply use ‘*’ or ‘’ (empty string).</p><br><p>The configuration system provides ‘config list’ and ‘config set’ commands to maintain these configuration values.</p><br><p>Configuration values themselves are always stored internally as strings. Convenience functions are provided to access these as String, Int, Float and Bool.</p><br><h3 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="-1" tabindex="-1"><a class="header-anchor" href="#-1" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="-2" tabindex="-1"><a class="header-anchor" href="#-2" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="-3" tabindex="-1"><a class="header-anchor" href="#-3" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="-4" tabindex="-1"><a class="header-anchor" href="#-4" aria-label="Permalink to &quot;&quot;">​</a></h3><h3 id="access-config-flash-filesystem" tabindex="-1">Access config flash filesystem <a class="header-anchor" href="#access-config-flash-filesystem" aria-label="Permalink to &quot;Access config flash filesystem&quot;">​</a></h3><p>You can read and write the flash content using the esptool.py, and you can mount the retrieved image using a loopback device to access the config store on your PC.</p><br><p>Example: to retrieve and mount the FAT filesystem using losetup:</p><br><p>$ cat partitions.csv</p><p># OVMS 16MB flash ESP32 Partition Table</p><p># Name, Type, SubType, Offset, Size</p><p>nvs, data, nvs, 0x9000, 0x4000</p><p>otadata, data, ota, 0xd000, 0x2000</p><p>phy_init, data, phy, 0xf000, 0x1000</p><p>factory, app, factory, 0x10000, 4M</p><p>ota_0, app, ota_0, , 4M</p><p>ota_1, app, ota_1, , 4M</p><p>store, data, fat, , 1M</p><br><p>$ bc</p><p>65536+(3*4*1024*1024)</p><p>==&gt; 12648448</p><p>1024*1024</p><p>==&gt; 1048576</p><br><p>$ ~/esp/esp-idf/components/esptool_py/esptool/esptool.py --port /dev/tty.SLAB_USBtoUART --baud 921600 read_flash 12648448 1048576 fatty</p><p>esptool.py v2.2.1</p><p>…</p><p>1048576 (100 %)</p><p>Read 1048576 bytes at 0xc10000 in 12.9 seconds (649.4 kbit/s)…</p><br><p>$ file fatty</p><p>fatty: DOS/MBR boot sector, code offset 0xfe+2, OEM-ID &quot;MSDOS5.0&quot;, Bytes/sector 4096, FAT 1, root entries 512, sectors 250 (volumes &lt;=32 MB) , Media descriptor 0xf8, sectors/FAT 1, sectors/track 63, heads 255, serial number 0x210000, unlabeled, FAT (1Y bit by descriptor)</p><br><p>$ mkdir f</p><p>$ losetup /dev/loop0 fatty</p><p>$ mount -t vfat /dev/loop0 f</p><p>$ ls -l f</p><p>drwxr-xr-x 0 root root 4096 Jan 1 1980 ovms_config</p><br><p>$ umount f</p><p>$ losetup -d /dev/loop0</p><br><p>On macOS, use hdiutil instead of losetup:</p><br><p>$ hdiutil attach -imagekey diskimage-class-CRawDiskImage -nomount fatty</p><p>/dev/disk11</p><p>$ mount_msdos /dev/disk11 f</p><p>$ ls -l f</p><p>drwxr-xr-x 0 root root 4096 Jan 1 1980 ovms_config</p><br><p>$ umount f</p><p>$ hdiutil detach /dev/disk11</p><p>“Disk11” ejected.</p><br><p>See esptool.py --help on writing back a modified image.</p><p>To wipe the entire flash, and re-flash with latest:</p><br><p>$ make erase_flash</p><p>$ make flash</p><br><p>You could probably just erase that one flash partition, but the above is quick and simple.</p><h2 id="module-circuit-design" tabindex="-1">Module Circuit Design <a class="header-anchor" href="#module-circuit-design" aria-label="Permalink to &quot;Module Circuit Design&quot;">​</a></h2><p>The OVMS v3 module circuit is designed to be extremely expandable, and to serve as the base for vehicle CAN bus hacking.</p><h3 id="main-board-overview" tabindex="-1">Main Board Overview <a class="header-anchor" href="#main-board-overview" aria-label="Permalink to &quot;Main Board Overview&quot;">​</a></h3><p><img src="https://lh7-us.googleusercontent.com/3a93ZiIBZxSXfDDGhgnaSt1DAqVT3zEvakja8cE2kHxKRWlgYPGf9bOXS-bUM09RgsxV3KGo4bUdH7X6_cBGQNyrNAyU7gbhb1Xpyx3keUimxZOuDmn2HW6QLev_NM3ff10tohNQ63u95g20gHeMBg" alt="ovmsv3main.png"></p><p>At the centre of the OVMS main board is an ESP32 WROOM-32 module. From there, we have modules for Storage, Power &amp; USB, and Expansion Connectors.</p><br><h3 id="wroom-32-and-support-circuits" tabindex="-1">WROOM-32 and Support Circuits <a class="header-anchor" href="#wroom-32-and-support-circuits" aria-label="Permalink to &quot;WROOM-32 and Support Circuits&quot;">​</a></h3><p><img src="https://lh7-us.googleusercontent.com/MHHjBBsPcKD-XfoPdcDLRSLvDmH3yDIbXg-tQMDLi7UStnyjD32AmbcmZo6mrAzModlgBp-0Z70P6CdnRrBFMNeWFMv5CqY1jUiGVRoz3it1m7aSUiGDxP8FzU99dvxw8_mTGh_PXJlG8KGnMJjl8g" alt="ovmsv3mcu.png"></p><br><h4 id="_128mb-external-spi-flash" tabindex="-1">128MB External SPI Flash<img src="https://lh7-us.googleusercontent.com/EtTNZ8uaxcu9QFOZYleILrA7ayicHt8MpjEkas_8vKtuo753008cOxLeKqU2M1VOZJlFwsR25ycr7YXzFhk8QubquZZ4r_14KEGFx7zbf6E0fNL8hQkm5dcUS7Mv2It75iMv3nVndXGvOFhteahlNQ" alt="ovmsv3mcu2.png"> <a class="header-anchor" href="#_128mb-external-spi-flash" aria-label="Permalink to &quot;128MB External SPI Flash![ovms\\_v3\\_mcu2.png](https://lh7-us.googleusercontent.com/EtTNZ8uaxcu9QFOZYleILrA7ayicHt8MpjEkas_8vKtuo753008cOxLeKqU2M1VOZJlFwsR25ycr7YXzFhk8QubquZZ4r_14KEGFx7zbf6E0fNL8hQkm5dcUS7Mv2It75iMv3nVndXGvOFhteahlNQ)&quot;">​</a></h4><p>The on-board 4MB SPI flash of the ESP32 WROOM-32 module is not used by OVMS v3. Instead, an external W32R128FV 128MB SPI flash is used for bootloader, firmware, and configuration storage. This is connected to the same SPI bus lines as the onboard 4MB flash, but uses a FL_CS2 (IO22) as the SPI chip select.</p><br><h4 id="max7317-gpio-expansion" tabindex="-1">MAX7317 GPIO Expansion <a class="header-anchor" href="#max7317-gpio-expansion" aria-label="Permalink to &quot;MAX7317 GPIO Expansion&quot;">​</a></h4><p><img src="https://lh7-us.googleusercontent.com/GzLULrrnTmNdGzh84PpjTpiH3y6_djkFymGKJeM7lzPZX-8wrJepfSvuMcn50NR7Ub7VU4RXAtRnsSWsqzDgq4qHGJVbIHxC_-T6MYnohvQYGH5tu0HNUlsKSYPSIlCKFX5GNkb18cfPEB9vqkj1tg" alt="ovmsv3mcu3.png"></p><p>To expand on the number of GPIO available, a MAX7317 GPIO expansion chip is used, and driven by the 2nd ESP32 SPI bus. This shares the same bus as the two MCP2515 CAN bus controllers, and has chip select on CP_CS3 (IO21). To allow this chip to co-exist with others on that shared SPI bus, a 74AHCIG125 tri-state buffer is used to isolate the SP_MISO line (driven from the same SP_CS3 line as the MAX7317 itself).</p><br><p>The MAX7317 provides 10 EGPIO pins (labelled P0 through P9), which can be configured as either input or output pins. The first few of these are reserved, and used by other modules in the OVMS v3 system.</p><p><br><br></p><table tabindex="0"><thead><tr><th>MAX7317 Pin Assignments</th><th></th><th></th></tr></thead><tbody><tr><td>MAX7317 EGPIO</td><td>Pin</td><td>Comment</td></tr><tr><td>P0</td><td>MDM_EN</td><td>Modem Enable Line (for expansion modem control)</td></tr><tr><td>P1</td><td>SW_CTL</td><td>Switched 12V control</td></tr><tr><td>P2</td><td>ESP32CAN_EN</td><td>ESP32 CAN SN65 Transceiver power control</td></tr><tr><td>P3</td><td>MDM_DTR</td><td>Modem DTR Line (for expansion modem control)</td></tr><tr><td>P4</td><td>EGPIO3</td><td>General purpose GPIO (available for expansion)</td></tr><tr><td>P5</td><td>EGPIO4</td><td>General purpose GPIO (available for expansion)</td></tr><tr><td>P6</td><td>EGPIO5</td><td>General purpose GPIO (available for expansion)</td></tr><tr><td>P7</td><td>EGPIO6</td><td>General purpose GPIO (available for expansion)</td></tr><tr><td>P8</td><td>EGPIO7</td><td>General purpose GPIO (available for expansion)</td></tr><tr><td>P9</td><td>EGPIO8</td><td>General purpose GPIO (available for expansion)</td></tr></tbody></table><p><br><br><br></p><h4 id="esp32-boot-flash-control-via-usb" tabindex="-1">ESP32 Boot/Flash Control via USB <a class="header-anchor" href="#esp32-boot-flash-control-via-usb" aria-label="Permalink to &quot;ESP32 Boot/Flash Control via USB&quot;">​</a></h4><p><br><img src="https://lh7-us.googleusercontent.com/GUaa-T6vJrL3DBCoavk15163Qkt7PH48togIvPGLKkwWCW9l6eDGgJN-RfKBIu4EOJlxR2shTsefYlJl6JJlDXOIo09mcFh8ieiocsIS9_KJn-Kxrln5vzbvkZh-IQnLlL9MY7e3vpFk7ti0nwHqaQ" alt="ovmsv3mcu4.png"></p><p>The DTR and RTS pins from CP2102 USB control lines are used in the normal ESP32 fashion to control bootloader boot/flash mode, using transceiver logic. These pins control the ESP32_EN and ESP32_IO0 pins during boot time (also controllable via the two push button switches on the circuit board).</p><p><br><br></p><h4 id="aoz1280ci-power" tabindex="-1">AOZ1280CI Power <a class="header-anchor" href="#aoz1280ci-power" aria-label="Permalink to &quot;AOZ1280CI Power&quot;">​</a></h4><p><img src="https://lh7-us.googleusercontent.com/eY5qOB5EgSqBEyqnFUMQb6MJRv6amQ4fsQb-OUy8ZEPcV48OeRrVxeMCC-4Mx9c0i4F5zW4UsXtUav0wkEYo2Q62IN1-gECxD2uycrihB7IRT9qtnah8__Y9CnMqajJzdDPLD6SWcgkUkqGJ9VFPOw" alt="ovmsv3mcu5.png"></p><p>An AOZ1280CI switched mode power supply chip is used to convert either USB 5V or external 12V incoming power to regulated 3.3V. Diodes are used for polarity protection, as well as to correctly protect the USB 5V side from external 12V power. A shared ground scheme is used.</p><p><br><br><br></p><h4 id="bts452r-switched-12v-power" tabindex="-1">BTS452R Switched 12V Power<img src="https://lh7-us.googleusercontent.com/ghuF4k6a-KzNvnjYjduGYHc__tfGlzu9EYyGrtvA0lWizenHuO8wE0mO0hQiyR2Wec4mqsssQVJOX2teSfjg96mx1MZ_7osUTW-01_KbJK0rb6PCj79EFepjXe4xh4ssaPjNC2FXdOJZne5KN9qakQ" alt="ovmsv3mcu7.png"> <a class="header-anchor" href="#bts452r-switched-12v-power" aria-label="Permalink to &quot;BTS452R Switched 12V Power![ovms\\_v3\\_mcu7.png](https://lh7-us.googleusercontent.com/ghuF4k6a-KzNvnjYjduGYHc__tfGlzu9EYyGrtvA0lWizenHuO8wE0mO0hQiyR2Wec4mqsssQVJOX2teSfjg96mx1MZ_7osUTW-01_KbJK0rb6PCj79EFepjXe4xh4ssaPjNC2FXdOJZne5KN9qakQ)&quot;">​</a></h4><br><p>A BTS452R, connected to SW_CTL on the MAX7317 GPIO expansion chip, is used to provide switched 12V power on the DA26 expansion connector.</p><br><p>Note that this is only switched the main external 12V power line, so will provide whatever power that line provides.</p><br><h4 id="cp2102-usb" tabindex="-1">CP2102 USB <a class="header-anchor" href="#cp2102-usb" aria-label="Permalink to &quot;CP2102 USB&quot;">​</a></h4><p><br><img src="https://lh7-us.googleusercontent.com/g1V5xXiES8jwSAsyhfFaa3JAn10HRdO0WUj1_AznHfb7NP0Ho7XeNzIIdTcNfZHL558V3hvCfzd7Q56AsqjwaqArhJQ6U2w4-FszjcXWNYwFumAfrlfuFU-nI_WPy6L3dsYwL4y6O5nYHGbsVTf8Hw" alt="ovmsv3mcu6.png"></p><p>A CP2102 USB-async chip is used for connection to the ESP32 primary asynchronous console port. This is used for terminal access, low-level chip and eFuse access, as well as firmware upload.</p><br><p>As previously described, the CSL_DTR and CSL_RTS lines are used for control of the ESP32 during boot, and can be used to reset the system and/or enable firmware download modes.</p><p><br><br><br><br><br><br><br><br><br><br></p><h4 id="micro-sd-card" tabindex="-1">Micro SD Card <a class="header-anchor" href="#micro-sd-card" aria-label="Permalink to &quot;Micro SD Card&quot;">​</a></h4><p><br><img src="https://lh7-us.googleusercontent.com/R2qyPC-iK0CKjYBdAefmrz4Zp1r7obFkbZ7q_3SrFY5q5Api_7CRo98MiADwW_SniDXU2IMwhwnXebWCIkkTyDhKNbAesmS1UokhrCCGhGKYMte37kLT7TCc-wihrMvWITsqI_0mZXRKA5xJ8A1mFw" alt="ovmsv3mcu8.png"></p><p>A standard Micro SD card is available on the third SPI bus of the ESP32. This is wired in both 1 and 4 line modes, and includes a SD_DET GPIO for detection of card insertion.</p><p><br><br><br><br><br></p><table tabindex="0"><thead><tr><th>ESP32 WROOM-32 Pin Assignments</th><th></th><th></th><th></th></tr></thead><tbody><tr><td>ESP32</td><td>Function</td><td>OVMS</td><td>Comment</td></tr><tr><td>1</td><td>GND1</td><td>GND</td><td>Signal Ground</td></tr><tr><td>2</td><td>+3V3</td><td>+3.3V</td><td>+3.3v from AOZ1280CI circuit</td></tr><tr><td>3</td><td>EN</td><td>ESP32_EN</td><td>ESP32 enable (reset) control</td></tr><tr><td>4</td><td>SENSOR_VP</td><td>ADC_IN</td><td>ADC voltage divider input</td></tr><tr><td>5</td><td>SENSOR_VN</td><td>SD_DET</td><td>SD CARD detect</td></tr><tr><td>6</td><td>IO34</td><td>SP_INT1</td><td>MCP2551 #1 interrupt line</td></tr><tr><td>7</td><td>IO35</td><td>SP_INT2</td><td>MCP2551 #2 interrupt line</td></tr><tr><td>8</td><td>IO32</td><td>EXP_1</td><td>ESP32 general purpose free expansion</td></tr><tr><td>9</td><td>IO33</td><td>EXP_2</td><td>ESP32 general purpose free expansion</td></tr><tr><td>10</td><td>IO25</td><td>CAN_TXD</td><td>ESP32 CAN TXD to SN65</td></tr><tr><td>11</td><td>IO26</td><td>CAN_RXD</td><td>ESP32 CAN RXD from SN65</td></tr><tr><td>12</td><td>IO27</td><td>SP_CS2</td><td>MCP2551 #2 CS line</td></tr><tr><td>13</td><td>IO14</td><td>SD_CLK</td><td>SD CARD clock</td></tr><tr><td>14</td><td>IO12</td><td>SD_DATA2</td><td>SD CARD DATA2</td></tr><tr><td>15</td><td>GND2</td><td>GND</td><td>Signal Ground</td></tr><tr><td>16</td><td>IO13</td><td>SD_DATA3</td><td>SD CARD DATA3</td></tr><tr><td>17</td><td>SD2</td><td>FL_HOLD</td><td>W32R128FV SPI Flash HOLD</td></tr><tr><td>18</td><td>SD3</td><td>FL_WP</td><td>W32R128FV SPI Flash WP</td></tr><tr><td>19</td><td>CMD</td><td>FL_CS1</td><td>WROOM-32 4MB SPI Flash CS</td></tr><tr><td>20</td><td>CLK</td><td>FL_SCK</td><td>W32R128FV SPI Flash SCK</td></tr><tr><td>21</td><td>SD0</td><td>FL_SDO</td><td>W32R128FV SPI Flash SDO</td></tr><tr><td>22</td><td>SD1</td><td>FL_SDI</td><td>W32R128FV SPI Flash SDI</td></tr><tr><td>23</td><td>IO15</td><td>SD_CMD</td><td>SD CARD CMD</td></tr><tr><td>24</td><td>IO2</td><td>SD_DATA0</td><td>SD CARD DATA0</td></tr><tr><td>25</td><td>IO0</td><td>ESP32_IO0</td><td>ESP32 IO0 Firmware ‘boot’ line</td></tr><tr><td>26</td><td>IO4</td><td>SD_DATA1</td><td>SD CARD DATA1</td></tr><tr><td>27</td><td>IO16</td><td>MDM_TXD</td><td>TX data to optional modem</td></tr><tr><td>28</td><td>IO17</td><td>MDM_RXD</td><td>RX data from optional modem</td></tr><tr><td>29</td><td>IO5</td><td>SP_CS1</td><td>MCP2551 #1 CS line</td></tr><tr><td>30</td><td>IO18</td><td>SP_CLK</td><td>SPI bus CLK</td></tr><tr><td>31</td><td>IO19</td><td>SP_MISO</td><td>SPI bus MISO</td></tr><tr><td>32</td><td>n/c</td><td>n/c</td><td><p><br></p></td></tr><tr><td>33</td><td>IO21</td><td>SP_CS3</td><td>MAX7317 CS line</td></tr><tr><td>34</td><td>RXD0</td><td>CSL_TXD</td><td>TXD to USB async console</td></tr><tr><td>35</td><td>TXD0</td><td>CSL_RXD</td><td>RXD from USB async console</td></tr><tr><td>36</td><td>IO22</td><td>FL_CS2</td><td>W32R128FV SPI Flash CS</td></tr><tr><td>37</td><td>IO23</td><td>SP_MOSI</td><td>SPI bus MOSI</td></tr><tr><td>38</td><td>GND3</td><td>GND</td><td>Signal Ground</td></tr></tbody></table><h3 id="can-buses" tabindex="-1">CAN Buses <a class="header-anchor" href="#can-buses" aria-label="Permalink to &quot;CAN Buses&quot;">​</a></h3><p>The OVMS v3 module has support for three CAN buses.</p><ul><li>CAN1 uses the ESP32’s own on-board CAN controller</li><li>CAN2 uses a MCP2515 SPI CAN controller</li><li>CAN3 uses a MCP2515 SPI CAN controller</li></ul><p>All three uses SN65 3.3v transceivers.</p><br><h4 id="can1-on-board" tabindex="-1">CAN1 - On Board<img src="https://lh7-us.googleusercontent.com/A8PKe7G7AG7XdO-T25yp2Z5f9hLsAQ8wFITAI1dEMrW6uodFl4EDDG1qjl-3tm_EJkevGWvvclDwZbmfBU6sg1mlgdxbi-Jpkxtl_0wi8DAiN2adaHRr3eddbFymN87Fz-xijMR7u84oDik_BWFmGw" alt="ovmsv3can1.png"> <a class="header-anchor" href="#can1-on-board" aria-label="Permalink to &quot;CAN1 - On Board![ovms\\_v3\\_can1.png](https://lh7-us.googleusercontent.com/A8PKe7G7AG7XdO-T25yp2Z5f9hLsAQ8wFITAI1dEMrW6uodFl4EDDG1qjl-3tm_EJkevGWvvclDwZbmfBU6sg1mlgdxbi-Jpkxtl_0wi8DAiN2adaHRr3eddbFymN87Fz-xijMR7u84oDik_BWFmGw)&quot;">​</a></h4><p>The CAN1 bus uses the ESP32 on-board CAN controller and an external SN65 3.3v transceiver. Power control of the transceiver is via the ESP32CAN_EN line of the MAX7317 GPIO expansion system.</p><br><h4 id="can2-and-can3-via-mcp2515" tabindex="-1">CAN2 and CAN3 via MCP2515 <a class="header-anchor" href="#can2-and-can3-via-mcp2515" aria-label="Permalink to &quot;CAN2 and CAN3 via MCP2515&quot;">​</a></h4><p><img src="https://lh7-us.googleusercontent.com/1ocazeH6B_Q8fn7Q-qHo8y6NNamqkgBy2V2fLp8wpn9vAPUxP-3JNJsVK7Z_rscgutzybw-4CvPLEq5p4uUHt3f34JTDym2XjRSeJzs8lpG9NrBPswzndG4kLsjA__iTVbZjPzEFRFvJ-Z-fML9RwA" alt="ovmsv3can2.png"></p><p>CAN2 and CAN3 are via MCP2515 SPI controllers and SN65 3.3v transceivers. Power control of the transceivers is via RX0BF/RX1BF GPIO outputs from the MCP2515 controllers.</p><br><h3 id="expansion" tabindex="-1">Expansion <a class="header-anchor" href="#expansion" aria-label="Permalink to &quot;Expansion&quot;">​</a></h3><p>There are three expansion connectors on the OVMS v3 module. The connections, and wiring, for these is as follows.</p><p><br><br></p><h4 id="internal-expansion-bus" tabindex="-1">Internal Expansion Bus<img src="https://lh7-us.googleusercontent.com/UbMqvGYbkBlSAR2tY8u0kZSbt2_pqxZUcbDvwdfpjXEcb32-vYt8CHoi0hDAnCpygqRQmzI_jjER2cYV8bau9e5gzkPUed1qzDXGK8JinYdoPL_GB4alffbDEGQ60nqXJ72GH2gb86uPmSJZBPs-ZA" alt="ovmsv3exp1.png"> <a class="header-anchor" href="#internal-expansion-bus" aria-label="Permalink to &quot;Internal Expansion Bus![ovms\\_v3\\_exp1.png](https://lh7-us.googleusercontent.com/UbMqvGYbkBlSAR2tY8u0kZSbt2_pqxZUcbDvwdfpjXEcb32-vYt8CHoi0hDAnCpygqRQmzI_jjER2cYV8bau9e5gzkPUed1qzDXGK8JinYdoPL_GB4alffbDEGQ60nqXJ72GH2gb86uPmSJZBPs-ZA)&quot;">​</a></h4><br><p>The internal expansion bus consists of two rows of 14 pins and is designed to be stackable. It exposes the EGPIO pins from the MAX7317 GPIO expansion chip, as well as available GPIO and bus pins direct from the ESP32 microcontroller on the ESP WROOM-32 module. Input/Output pins are also available from/to the DA26 external expansion connector.</p><p><br><br></p><h4 id="da26-external-expansion-connector" tabindex="-1">DA26 External Expansion Connector<img src="https://lh7-us.googleusercontent.com/wEOgYAmcA5ajmwqnscsPBU_EyExp_bqJqf64oyAUwkSKKcaOmG92deJiFDUdHw_aBnhCgh7fcBlVjq0bMd18vOovOUgzAkxCCPIfDBhUOX7yl7sQ565xP0wOLDa39fFAExM8fv2-SrpsujspE__ZKw" alt="ovmsv3exp2.png"> <a class="header-anchor" href="#da26-external-expansion-connector" aria-label="Permalink to &quot;DA26 External Expansion Connector![ovms\\_v3\\_exp2.png](https://lh7-us.googleusercontent.com/wEOgYAmcA5ajmwqnscsPBU_EyExp_bqJqf64oyAUwkSKKcaOmG92deJiFDUdHw_aBnhCgh7fcBlVjq0bMd18vOovOUgzAkxCCPIfDBhUOX7yl7sQ565xP0wOLDa39fFAExM8fv2-SrpsujspE__ZKw)&quot;">​</a></h4><br><p>The DA26 external expansion connector is designed to be used for connection to external devices, for expansion of core functionality It exposes the GEP 1..7 pins from the internal expansion connector, as well as all CAN buses, power sources, etc.</p><br><p>In particular, a switched 12V power supply is available from this connector.</p><p><br><br></p><table tabindex="0"><thead><tr><th>DA26 Expansion Connector Pin Assignments</th><th></th><th></th></tr></thead><tbody><tr><td>Pin</td><td>Function</td><td>Comment</td></tr><tr><td>1</td><td>MDM_RXD</td><td>Modem receive data line</td></tr><tr><td>2</td><td>MDM_EN</td><td>Modem enable control line</td></tr><tr><td>3</td><td>GEP_6</td><td>General Expansion Output #6</td></tr><tr><td>4</td><td>GEP_4</td><td>General Expansion Output #4</td></tr><tr><td>5</td><td>CAN0_L</td><td>First CAN bus (CAN1) low</td></tr><tr><td>6</td><td>CAN2_L</td><td>Third CAN bus (CAN3) low</td></tr><tr><td>7</td><td>CAN1_L</td><td>Second CAN bus (CAN2) low</td></tr><tr><td>8</td><td>GND</td><td>Ground signal line</td></tr><tr><td>9</td><td>EXT_12V</td><td>External 12V power supply</td></tr><tr><td>10</td><td>EXP_1</td><td>ESP32 general purpose free expansion</td></tr><tr><td>11</td><td>EXP_2</td><td>ESP32 general purpose free expansion</td></tr><tr><td>12</td><td>MDM_TXD</td><td>Modem transmit data line</td></tr><tr><td>13</td><td>GEP_5</td><td>General Expansion Output #5</td></tr><tr><td>14</td><td>n/c</td><td><p><br></p></td></tr><tr><td>15</td><td>CAN0_H</td><td>First CAN bus (CAN1) high</td></tr><tr><td>16</td><td>CAN2_H</td><td>Third CAN bus (CAN3) high</td></tr><tr><td>17</td><td>CAN1_H</td><td>Second CAN bus (CAN2) high</td></tr><tr><td>18</td><td>SW_12V</td><td>Switched 12V</td></tr><tr><td>19</td><td>GEP_1</td><td>General Expansion Output #1</td></tr><tr><td>20</td><td>GEP_2</td><td>General Expansion Output #2</td></tr><tr><td>21</td><td>GEP_7</td><td>General Expansion Output #7</td></tr><tr><td>22</td><td>GEP_3</td><td>General Expansion Output #3</td></tr><tr><td>23</td><td>GND</td><td>Ground signal line</td></tr><tr><td>24</td><td>+3.3V</td><td>Regulated 3.3v power</td></tr><tr><td>25</td><td>n/c</td><td><p><br></p></td></tr><tr><td>26</td><td>n/c</td><td><p><br></p></td></tr></tbody></table><p><br><br></p><h4 id="db9-external-expansion-connector" tabindex="-1">DB9 External Expansion Connector<img src="https://lh7-us.googleusercontent.com/NBjETVjkpPuXlqoGyT6XV8WFJjaSHRRysvd4d8gpFQOAE8hy-auQS2HbnAJL3C9Fuy7x6otZCOcF7QyIK_WdyDN6FHRXYFVbLDOJmaW9S6s84vQbo9bwGM337RV839E5bb8sb2HEyXD1cKgw2vwLVQ" alt="ovmsv3exp3.png"> <a class="header-anchor" href="#db9-external-expansion-connector" aria-label="Permalink to &quot;DB9 External Expansion Connector![ovms\\_v3\\_exp3.png](https://lh7-us.googleusercontent.com/NBjETVjkpPuXlqoGyT6XV8WFJjaSHRRysvd4d8gpFQOAE8hy-auQS2HbnAJL3C9Fuy7x6otZCOcF7QyIK_WdyDN6FHRXYFVbLDOJmaW9S6s84vQbo9bwGM337RV839E5bb8sb2HEyXD1cKgw2vwLVQ)&quot;">​</a></h4><br><p>The OVMS v3 module includes a DB9 external expansion connector, compatible with the OVMS v2 design but exposing the extra two CAN buses available in OVMS v3.</p><p><br><br><br><br></p><table tabindex="0"><thead><tr><th>DB9 Expansion Connector Pin Assignments</th><th></th><th></th></tr></thead><tbody><tr><td>Pin</td><td>Function</td><td>Comment</td></tr><tr><td>1</td><td>n/c</td><td><p><br></p></td></tr><tr><td>2*</td><td>CAN0_L</td><td>First CAN bus (CAN1) low</td></tr><tr><td>3*</td><td>GND</td><td>Signal ground</td></tr><tr><td>4</td><td>CAN1_L</td><td>Second CAN bus (CAN2) low</td></tr><tr><td>5</td><td>CAN1_H</td><td>Second CAN bus (CAN2) high</td></tr><tr><td>6</td><td>CAN2_L</td><td>Third CAN bus (CAN3) low</td></tr><tr><td>7*</td><td>CAN0_H</td><td>First CAN bus (CAN1) high</td></tr><tr><td>8</td><td>CAN2_H</td><td>Third CAN bus (CAN3) high</td></tr><tr><td>9*</td><td>EXT_12V</td><td>External 12v power supply</td></tr></tbody></table><br><p>* OVMS v2 compatible pin</p><h2 id="conclusions" tabindex="-1">Conclusions <a class="header-anchor" href="#conclusions" aria-label="Permalink to &quot;Conclusions&quot;">​</a></h2><br><p><a href="../../.gitbook/assets/OVMS%20v3%20Developer%20Guide.pdf">OVMS v3 Developer Guide.pdf</a></p><p><a href="../../.gitbook/assets/OVMS%20v3%20Developer%20Guide.rtf">OVMS v3 Developer Guide.rtf</a></p>',797)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
